+struct ReplayCollector {
+    ticks: Arc<Mutex<Vec<ReplayTickRecord>>>,
+}
+
+impl ReplayCollector {
+    fn new() -> (Self, Arc<Mutex<Vec<ReplayTickRecord>>>) {
+        let ticks = Arc::new(Mutex::new(Vec::new()));
+        (Self { ticks: Arc::clone(&ticks) }, ticks)
