+            "Action(agent={:?}, lw={:.3}, rw={:.3}, boost={}, spike={:?}, sound={:.3}, give={:.3})",
+            event.agent_id,
+            left_wheel,
+            right_wheel,
+            boost,
+            spike_target,
+            sound_level,
+            give_intent
+        ),
+        ReplayEventKind::RngSample {
+            scope,
+            range_min,
+            range_max,
+            value,
+        } => format!(
+            "RngSample(scope={:?}, min={:.3}, max={:.3}, value={:.3})",
